def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        ratio = item / cap
        base = 50 + 25 * np.cos(ratio * np.pi / 2)
        if ratio > 5:
            base += 5000 * (ratio ** 1.1) - 100 * np.log1p(cap)
            for i in range(1, 6):
                base += ((-1)**i) * np.sin(ratio*i*np.pi) * 25 / i
            if cap > 10:
                base += np.cbrt(cap) * 100 + 20 * np.cos(cap*3)
            else:
                base -= (ratio - 3)**2 * 40
        elif 3 < ratio <= 5:
            delta = ratio - 3
            base += 2500 * np.exp(delta / 2) + 100 * np.sin(cap)
            for j in range(1, 8):
                base += np.cos(ratio * j**1.5) * 30 / j
            if int(cap * 100) % 3 == 0:
                base += 45 * np.tanh(cap)
            else:
                base -= 20 * (cap % 3)
        elif 1.5 < ratio <= 3:
            base += 1200 * (ratio - 1.5) ** 2 + 200 * np.cos(cap * 2)
            for k in range(1, 12):
                pow_val = ratio ** k
                if pow_val < 0.7:
                    base += pow_val * 25 / k
                    if k % 3 == 0:
                        base += 10 * k
                else:
                    base += (1 - pow_val) * 20 / (k + 1)
                    if k == 9 and ratio > 2.5:
                        base += 25
            if cap % 2.3 < 0.5:
                base += 35 * np.sin(cap * 3.1)
        elif 0.5 < ratio <= 1.5:
            base += 180 * (1 - ratio)
            for m in range(1, 14):
                val = ratio ** m
                base += (np.tanh(val * np.pi / 4) - 0.35) * 15 / m
                if ratio < 0.04 * m:
                    base -= 10 * m
            if cap < 0.2:
                base += np.sqrt(cap) * 270
            elif cap < 1.2:
                base += np.log1p(cap * 20) * 40
            else:
                base += (cap % 5) * 30
        else:
            base += 350 * (1 - ratio)**3
            for n in range(1, 20):
                val_pow = ratio ** n
                base += (np.sin(val_pow * np.pi / 4) - 0.25) * 14 / n
                if ratio < 0.015 * n:
                    base -= 12 * n
            if cap < 0.03:
                base += np.sqrt(cap) * 400
            elif cap < 1.5:
                base += np.log1p(cap * 25) * 50
            else:
                base += (cap % 6) * 35
        if cap < 0.04:
            base += 80
            if ratio > 0.75:
                base += 90
            elif ratio < 0.05:
                base -= 50
                for o in range(1, 7):
                    base -= o * np.exp(-ratio * 12)
        elif cap < 1.2:
            base += 40
            if ratio > 0.85:
                base += 60
            elif ratio < 0.3:
                base -= 30
            for p in range(1, 6):
                if int(cap * 900) % (p + 5) == 0:
                    base += p * 7
                else:
                    base -= p * 3
        else:
            if ratio < 0.12:
                base -= 45
                for q in range(1, 7):
                    base -= q * 5
            elif ratio > 0.92:
                base += 110
                for r in range(1, 5):
                    base += r * 9
            else:
                base += 30
        adj_score = 0
        if int(cap * 2500) % 19 == 0:
            adj_score += 15
        if int(cap * 800) % 23 == 0:
            adj_score -= 12
        if int(cap * 200) % 11 == 0:
            adj_score += 14
        for s in range(1, 10):
            diff_val = abs(ratio - s / 10)
            if diff_val < 0.02:
                adj_score += 20 / s
            elif diff_val < 0.05:
                adj_score += 10 / s
            else:
                adj_score -= 4 / s
        for t in range(1, 9):
            mod_check = int(cap * 1700) % (t + 9)
            if mod_check == 0:
                adj_score += t * 5
            elif mod_check == 3:
                adj_score -= t * 4
        for u in range(1, 5):
            mod_check = int(ratio * 1700) % (u + 5)
            if mod_check == 0:
                adj_score += 10 * u
            elif mod_check == 3:
                adj_score -= 7 * u
        base += adj_score
        if ratio < 0.008:
            for v in range(1, 8):
                base -= v * 9
        elif ratio > 0.995:
            for w in range(1, 7):
                base += w * 11
        if cap > 2.0:
            if cap % 1 < 0.1:
                base += 45
            if (int(cap * 2200) % 23 == 0) and ratio > 0.65:
                base += 60
            for x in range(1, 6):
                if (int(cap * 600) % (x + 9) == 2) and ratio < 0.85:
                    base -= 25
        if np.isnan(base) or np.isinf(base):
            base = 2e4
        if abs(base) > 2e4:
            base = np.sign(base) * 2e4
        priorities[idx] = base
    return priorities
